const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;700;900&family=Rajdhani:wght@300;400;500;600;700&family=Share+Tech+Mono&display=swap');
*{margin:0;padding:0;box-sizing:border-box;}
:root{--bg:#020a14;--bg2:#050f1e;--bg3:#071628;--cyan:#00d4ff;--green:#22d3a0;--orange:#f97316;--purple:#a855f7;--gold:#fbbf24;--text:#c8e6f4;--text2:#7aaec8;--border:rgba(0,212,255,0.15);--card-bg:rgba(5,20,40,0.85);}
html,body{height:100%;overflow:hidden;background:var(--bg);}
#root{height:100%;}
.etf{font-family:'Rajdhani',sans-serif;color:var(--text);height:100vh;display:flex;flex-direction:column;position:relative;overflow:hidden;background:var(--bg);}
.etf::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.03) 2px,rgba(0,0,0,0.03) 4px);pointer-events:none;z-index:9999;}
.bg-grid{position:fixed;inset:0;background-image:linear-gradient(rgba(0,212,255,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,212,255,0.03) 1px,transparent 1px);background-size:50px 50px;pointer-events:none;}
.navbar{display:flex;align-items:center;padding:0 28px;height:54px;background:rgba(2,10,20,0.97);border-bottom:1px solid var(--border);position:relative;z-index:100;flex-shrink:0;gap:4px;}
.nav-logo{font-family:'Orbitron',sans-serif;font-size:13px;font-weight:900;color:var(--cyan);letter-spacing:3px;margin-right:32px;text-shadow:0 0 20px var(--cyan);white-space:nowrap;}
.nav-logo span{color:#fff;}
.nav-links{display:flex;gap:2px;flex:1;}
.nl{padding:8px 16px;font-family:'Orbitron',sans-serif;font-size:10px;font-weight:600;letter-spacing:2px;color:var(--text2);cursor:pointer;border:1px solid transparent;transition:all .2s;background:transparent;white-space:nowrap;}
.nl:hover{color:var(--cyan);border-color:var(--border);}
.nl.active{color:var(--cyan);border-color:var(--cyan);background:rgba(0,212,255,0.08);text-shadow:0 0 10px var(--cyan);position:relative;}
.nl.active::after{content:'';position:absolute;bottom:-1px;left:0;right:0;height:1px;background:var(--cyan);box-shadow:0 0 8px var(--cyan);}
.nav-r{display:flex;align-items:center;gap:12px;font-size:11px;font-family:'Share Tech Mono',monospace;margin-left:auto;}
.nav-xp{color:var(--gold);font-weight:700;}
.nb{padding:3px 10px;border:1px solid var(--border);color:var(--text2);font-size:9px;letter-spacing:1px;white-space:nowrap;}
.content{flex:1;overflow:hidden;position:relative;}

/* HOME */
.home{height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;position:relative;overflow:hidden;}
.home-bg{position:absolute;inset:0;background:radial-gradient(ellipse at 30% 50%,rgba(0,100,200,0.12) 0%,transparent 60%),radial-gradient(ellipse at 70% 30%,rgba(100,0,200,0.08) 0%,transparent 50%);}
.home-title{text-align:center;z-index:2;animation:fadeInUp .8s ease both;}
.eyebrow{font-family:'Share Tech Mono',monospace;font-size:11px;color:var(--cyan);letter-spacing:8px;margin-bottom:16px;opacity:.7;}
.h1{font-family:'Orbitron',sans-serif;font-size:clamp(38px,5vw,68px);font-weight:900;line-height:1.0;text-transform:uppercase;letter-spacing:4px;}
.h1 .l1{color:#fff;display:block;}
.h1 .l2{color:var(--cyan);text-shadow:0 0 40px rgba(0,212,255,0.5);display:block;}
.home-sub{margin-top:14px;font-size:16px;color:var(--text2);letter-spacing:2px;}
.home-chars{display:flex;gap:20px;margin-top:48px;z-index:2;animation:fadeInUp .8s .3s ease both;opacity:0;animation-fill-mode:forwards;}
.hcm{width:96px;display:flex;flex-direction:column;align-items:center;gap:8px;cursor:pointer;transition:transform .2s;}
.hcm:hover{transform:translateY(-8px);}
.hcm-img{width:80px;height:100px;object-fit:cover;object-position:top;border:2px solid var(--border);clip-path:polygon(10% 0,100% 0,100% 90%,90% 100%,0 100%,0 10%);}
.hcm-name{font-size:8px;font-family:'Orbitron',sans-serif;letter-spacing:1px;color:var(--text2);}
.home-cta{display:flex;gap:16px;margin-top:36px;z-index:2;animation:fadeInUp .8s .5s ease both;opacity:0;animation-fill-mode:forwards;}
.btn-p{padding:13px 36px;font-family:'Orbitron',sans-serif;font-size:11px;font-weight:700;letter-spacing:3px;color:#000;background:var(--cyan);border:none;cursor:pointer;clip-path:polygon(8px 0,100% 0,100% calc(100% - 8px),calc(100% - 8px) 100%,0 100%,0 8px);transition:all .2s;text-transform:uppercase;}
.btn-p:hover{background:#fff;box-shadow:0 0 30px rgba(0,212,255,0.6);}
.btn-s{padding:13px 36px;font-family:'Orbitron',sans-serif;font-size:11px;font-weight:700;letter-spacing:3px;color:var(--cyan);background:transparent;border:1px solid var(--cyan);cursor:pointer;clip-path:polygon(8px 0,100% 0,100% calc(100% - 8px),calc(100% - 8px) 100%,0 100%,0 8px);transition:all .2s;text-transform:uppercase;}
.btn-s:hover{background:rgba(0,212,255,0.1);}
.home-stats{position:absolute;bottom:28px;display:flex;gap:56px;z-index:2;}
.stat{text-align:center;}
.stat-n{font-family:'Orbitron',sans-serif;font-size:26px;font-weight:900;color:var(--cyan);}
.stat-l{font-size:11px;color:var(--text2);letter-spacing:2px;margin-top:3px;}

/* CHAR SELECT */
.chars-screen{height:100%;display:flex;position:relative;overflow:hidden;}
.cs-bg-img{position:absolute;inset:0;background-size:cover;background-position:top center;transition:all .5s ease;filter:brightness(0.35) saturate(1.2);}
.cs-overlay{position:absolute;inset:0;background:linear-gradient(to right,rgba(2,10,20,0.97) 0%,rgba(2,10,20,0.7) 55%,rgba(2,10,20,0.2) 100%);}
.cs-left{position:relative;z-index:5;width:56%;padding:24px 36px;display:flex;flex-direction:column;}
.cs-header{margin-bottom:20px;}
.cs-tabs{display:flex;gap:22px;margin-bottom:6px;}
.cs-tab{font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:3px;color:var(--text2);cursor:pointer;padding-bottom:4px;border-bottom:2px solid transparent;transition:all .2s;}
.cs-tab.act{color:var(--cyan);border-color:var(--cyan);}
.cs-title{font-family:'Orbitron',sans-serif;font-size:30px;font-weight:900;color:#fff;letter-spacing:2px;}
.cs-strip{display:flex;gap:10px;padding:6px 0;overflow-x:auto;scrollbar-width:none;}
.cs-strip::-webkit-scrollbar{display:none;}
.cc{flex-shrink:0;width:118px;cursor:pointer;position:relative;transition:all .25s;}
.cc-inner{width:100%;height:158px;overflow:hidden;border:2px solid rgba(255,255,255,0.1);position:relative;clip-path:polygon(0 0,100% 0,100% 88%,88% 100%,0 100%);}
.cc.sel .cc-inner{box-shadow:0 0 22px var(--cg,rgba(0,212,255,0.3));}
.cc-img{width:100%;height:100%;object-fit:cover;object-position:top;filter:brightness(0.7);transition:all .3s;}
.cc.sel .cc-img,.cc:hover .cc-img{filter:brightness(1);}
.cc-lbl{position:absolute;bottom:0;left:0;right:0;padding:6px 8px;background:linear-gradient(transparent,rgba(0,0,0,0.9));font-family:'Orbitron',sans-serif;font-size:8px;letter-spacing:1px;color:#fff;}
.cc-pts{font-size:9px;margin-top:1px;}
.cc.sel::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:var(--cc,var(--cyan));box-shadow:0 0 10px var(--cg);}
.new-badge{position:absolute;top:5px;right:5px;background:var(--cyan);color:#000;font-family:'Orbitron',sans-serif;font-size:7px;font-weight:900;padding:2px 5px;}
.cs-detail{margin-top:20px;flex:1;display:flex;flex-direction:column;gap:14px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:var(--border) transparent;}
.cs-badge{display:inline-flex;align-items:center;gap:8px;padding:5px 14px;border:1px solid var(--cc,var(--cyan));color:var(--cc,var(--cyan));font-family:'Orbitron',sans-serif;font-size:9px;letter-spacing:3px;}
.cs-quote{font-size:14px;color:var(--text2);font-style:italic;line-height:1.6;padding-left:12px;border-left:2px solid var(--cc,var(--cyan));}
.nature-wrap{display:flex;flex-wrap:wrap;gap:7px;}
.nt{padding:4px 12px;border:1px solid rgba(255,255,255,0.1);font-size:11px;color:var(--text2);letter-spacing:1px;}
.bonus-box{padding:12px 16px;background:rgba(0,0,0,0.4);border:1px solid rgba(255,255,255,0.06);}
.bonus-t{font-family:'Orbitron',sans-serif;font-size:9px;letter-spacing:2px;color:var(--text2);margin-bottom:5px;}
.bonus-v{font-size:12px;line-height:1.5;}
.xp-bar{height:4px;background:rgba(255,255,255,0.08);margin-top:6px;}
.xp-fill{height:100%;transition:width 1s ease;box-shadow:0 0 8px var(--cg);}
.cs-actions{display:flex;gap:12px;padding-top:4px;}
.cs-right{position:absolute;right:0;top:0;bottom:0;width:50%;overflow:hidden;z-index:3;}
.cs-full{width:100%;height:100%;object-fit:cover;object-position:top center;transition:all .5s ease;}
.cs-right-ov{position:absolute;inset:0;background:linear-gradient(to right,rgba(2,10,20,0.75) 0%,transparent 35%),linear-gradient(to top,rgba(2,10,20,0.7) 0%,transparent 40%);}
.cs-ri{position:absolute;bottom:36px;right:36px;text-align:right;}
.cs-ri-role{font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:3px;margin-bottom:7px;}
.cs-ri-name{font-family:'Orbitron',sans-serif;font-size:22px;font-weight:900;color:#fff;}
.stars{display:flex;gap:3px;}

/* LEVELS */
.lvls{height:100%;padding:28px 36px;display:flex;flex-direction:column;overflow:hidden;}
.lvls-hdr{margin-bottom:20px;}
.lvls-title{font-family:'Orbitron',sans-serif;font-size:24px;font-weight:900;color:#fff;letter-spacing:3px;}
.lvls-sub{font-size:13px;color:var(--text2);margin-top:4px;}
.lvls-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;flex:1;overflow-y:auto;scrollbar-width:thin;scrollbar-color:var(--border) transparent;padding-right:4px;}
.lcard{position:relative;padding:22px;background:var(--card-bg);border:1px solid var(--border);clip-path:polygon(0 0,100% 0,100% calc(100% - 14px),calc(100% - 14px) 100%,0 100%);transition:all .25s;overflow:hidden;min-height:160px;}
.lcard.open:hover{border-color:var(--lc,var(--cyan));transform:translateY(-3px);box-shadow:0 8px 30px rgba(0,0,0,0.5);cursor:pointer;}
.lcard.locked{opacity:0.5;}
.lcard.final{grid-column:span 3;min-height:120px;}
.lv-sub{font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:3px;color:var(--lc,var(--cyan));margin-bottom:7px;}
.lv-icon{font-size:30px;margin-bottom:7px;}
.lv-title{font-family:'Orbitron',sans-serif;font-size:17px;font-weight:700;color:#fff;margin-bottom:5px;}
.lv-desc{font-size:12px;color:var(--text2);line-height:1.5;}
.lv-char{position:absolute;top:14px;right:14px;display:flex;flex-direction:column;align-items:flex-end;gap:3px;}
.lv-char-img{width:38px;height:48px;object-fit:cover;object-position:top;border:1px solid var(--lc,var(--cyan));}
.lv-char-n{font-size:8px;font-family:'Orbitron',sans-serif;letter-spacing:1px;}
.lv-lock{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.25);font-size:26px;opacity:0.4;}
.lv-prog{position:absolute;bottom:0;left:0;right:0;height:3px;background:rgba(255,255,255,0.05);}
.lv-prog-fill{height:100%;box-shadow:0 0 6px var(--lc,var(--cyan));}
.lv-sc{position:absolute;top:14px;left:14px;padding:2px 9px;background:rgba(0,0,0,0.7);border:1px solid var(--lc,var(--cyan));font-family:'Share Tech Mono',monospace;font-size:11px;}

/* GAME */
.game{height:100%;display:flex;overflow:hidden;position:relative;}
.g-sidebar{width:264px;flex-shrink:0;background:rgba(2,8,18,0.95);border-right:1px solid var(--border);display:flex;flex-direction:column;padding:18px;gap:14px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:var(--border) transparent;}
.g-portrait{width:100%;height:170px;object-fit:cover;object-position:top;}
.g-badge{padding:5px 10px;font-family:'Orbitron',sans-serif;font-size:8px;letter-spacing:2px;text-align:center;border-width:1px;border-style:solid;}
.g-cname{font-family:'Orbitron',sans-serif;font-size:13px;color:#fff;font-weight:700;}
.g-crole{font-size:11px;color:var(--text2);}
.g-bonus{padding:10px 12px;background:rgba(0,0,0,0.4);border:1px solid rgba(255,255,255,0.06);}
.g-bonus-t{font-size:9px;font-family:'Orbitron',sans-serif;letter-spacing:2px;color:var(--text2);margin-bottom:5px;}
.g-bonus-v{font-size:11px;line-height:1.5;}
.g-tips{font-size:12px;color:var(--text2);line-height:1.7;flex:1;}
.g-main{flex:1;display:flex;flex-direction:column;padding:26px;gap:16px;overflow:hidden;}
.g-lbadge{font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:4px;}
.g-ctitle{font-family:'Orbitron',sans-serif;font-size:26px;font-weight:900;color:#fff;}
.g-ctx{padding:14px 18px;background:rgba(255,255,255,0.03);border-left:3px solid var(--gc,var(--cyan));font-size:13px;color:var(--text2);line-height:1.7;}
.g-task{padding:14px 18px;background:rgba(0,0,0,0.4);border:1px solid var(--gc,var(--cyan));}
.g-task-l{font-family:'Orbitron',sans-serif;font-size:9px;letter-spacing:3px;margin-bottom:5px;}
.g-task-t{font-size:14px;color:#fff;font-weight:600;}
.g-input-area{flex:1;display:flex;flex-direction:column;gap:8px;min-height:0;}
.g-ta{flex:1;width:100%;background:rgba(0,0,0,0.55);border:1px solid var(--border);color:var(--text);padding:14px;font-family:'Rajdhani',sans-serif;font-size:14px;line-height:1.7;resize:none;outline:none;transition:border-color .2s;min-height:0;}
.g-ta:focus{border-color:var(--gc,var(--cyan));}
.g-ta::placeholder{color:rgba(120,160,200,0.3);}
.g-footer{display:flex;align-items:center;gap:14px;flex-wrap:wrap;flex-shrink:0;}
.g-wc{font-family:'Share Tech Mono',monospace;font-size:12px;color:var(--text2);}
.g-wc.ok{color:var(--green);}
.g-timer{font-family:'Share Tech Mono',monospace;font-size:18px;font-weight:700;padding:7px 14px;border:1px solid var(--border);}
.g-timer.warn{color:#f97316;border-color:#f97316;}
.g-timer.danger{color:#ef4444;border-color:#ef4444;animation:pulse .5s infinite;}
.g-sub{padding:11px 28px;font-family:'Orbitron',sans-serif;font-size:11px;font-weight:700;letter-spacing:3px;color:#000;border:none;cursor:pointer;clip-path:polygon(6px 0,100% 0,100% calc(100% - 6px),calc(100% - 6px) 100%,0 100%,0 6px);transition:all .2s;text-transform:uppercase;}
.g-sub:hover:not(:disabled){filter:brightness(1.15);box-shadow:0 0 20px rgba(0,212,255,0.4);}
.g-sub:disabled{opacity:0.4;cursor:not-allowed;}
.g-exit{padding:11px 18px;font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:2px;color:var(--text2);background:transparent;border:1px solid var(--border);cursor:pointer;transition:all .2s;}
.g-exit:hover{border-color:var(--cyan);color:var(--cyan);}

/* RESULT */
.res-ov{position:absolute;inset:0;background:rgba(2,10,20,0.96);display:flex;align-items:center;justify-content:center;z-index:50;animation:fadeIn .3s ease;}
.res-box{max-width:560px;width:90%;padding:36px;border:1px solid var(--gc,var(--cyan));background:var(--card-bg);position:relative;clip-path:polygon(0 0,100% 0,100% calc(100% - 20px),calc(100% - 20px) 100%,0 100%);}
.res-title{font-family:'Orbitron',sans-serif;font-size:20px;font-weight:900;margin-bottom:8px;}
.res-ring{width:110px;height:110px;margin:16px auto;position:relative;display:flex;align-items:center;justify-content:center;}
.res-ring svg{position:absolute;inset:0;transform:rotate(-90deg);}
.res-num{font-family:'Orbitron',sans-serif;font-size:30px;font-weight:900;}
.res-br{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin:14px 0;}
.rb{display:flex;justify-content:space-between;padding:7px 11px;background:rgba(0,0,0,0.3);border:1px solid rgba(255,255,255,0.05);font-size:12px;}
.rb-v{font-family:'Share Tech Mono',monospace;}
.res-fb{font-size:13px;color:var(--text2);line-height:1.7;margin-top:10px;padding:12px;border-left:2px solid var(--gc,var(--cyan));}
.res-acts{display:flex;gap:10px;margin-top:20px;justify-content:flex-end;flex-wrap:wrap;}

/* ACHIEVEMENTS */
.ach{height:100%;padding:28px 36px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:var(--border) transparent;}
.a-title{font-family:'Orbitron',sans-serif;font-size:24px;font-weight:900;color:#fff;letter-spacing:3px;margin-bottom:5px;}
.a-sub{font-size:13px;color:var(--text2);margin-bottom:22px;}
.a-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;}
.acard{padding:18px;background:var(--card-bg);border:1px solid var(--border);transition:all .2s;position:relative;overflow:hidden;}
.acard.earned{border-color:var(--gold);}
.acard.earned::after{content:'';position:absolute;top:0;right:0;width:0;height:0;border-style:solid;border-width:0 28px 28px 0;border-color:transparent var(--gold) transparent transparent;}
.a-icon{font-size:30px;margin-bottom:9px;}
.a-t{font-family:'Orbitron',sans-serif;font-size:11px;font-weight:700;color:#fff;margin-bottom:3px;}
.a-d{font-size:11px;color:var(--text2);line-height:1.5;}
.a-xp{margin-top:7px;font-family:'Share Tech Mono',monospace;font-size:11px;}
.a-lock{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.4);font-size:18px;opacity:0.4;}
.a-bar-wrap{margin-top:22px;padding:18px 22px;background:var(--card-bg);border:1px solid var(--border);display:flex;align-items:center;gap:22px;}
.a-bar{flex:1;height:8px;background:rgba(255,255,255,0.05);}
.a-bar-fill{height:100%;background:var(--gold);box-shadow:0 0 10px var(--gold);transition:width 1s ease;}

/* SETTINGS */
.settings{height:100%;padding:28px 36px;display:flex;gap:36px;overflow:hidden;}
.st-left{width:280px;display:flex;flex-direction:column;gap:10px;}
.st-title{font-family:'Orbitron',sans-serif;font-size:24px;font-weight:900;color:#fff;letter-spacing:3px;margin-bottom:20px;}
.st-sec{padding:14px 18px;background:var(--card-bg);border:1px solid var(--border);cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:12px;}
.st-sec:hover,.st-sec.act{border-color:var(--cyan);background:rgba(0,212,255,0.05);}
.st-sec-ic{font-size:16px;width:22px;text-align:center;}
.st-sec-l{font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:2px;color:var(--text2);}
.st-sec.act .st-sec-l{color:var(--cyan);}
.st-right{flex:1;padding:22px;background:var(--card-bg);border:1px solid var(--border);}
.st-row{display:flex;align-items:center;justify-content:space-between;padding:12px 0;border-bottom:1px solid rgba(255,255,255,0.04);}
.st-row-l{font-size:14px;color:var(--text);}
.toggle{width:42px;height:22px;background:rgba(255,255,255,0.08);border:1px solid var(--border);cursor:pointer;position:relative;transition:all .2s;}
.toggle.on{background:rgba(0,212,255,0.2);border-color:var(--cyan);}
.toggle::after{content:'';position:absolute;top:3px;left:3px;width:14px;height:14px;background:var(--text2);transition:all .2s;}
.toggle.on::after{left:23px;background:var(--cyan);}
.st-sel{background:rgba(0,0,0,0.4);border:1px solid var(--border);color:var(--text);padding:5px 10px;font-family:'Rajdhani',sans-serif;font-size:13px;outline:none;}
.st-slider{width:140px;accent-color:var(--cyan);}

/* HOW TO PLAY */
.htp{height:100%;padding:28px 36px;overflow-y:auto;scrollbar-width:thin;scrollbar-color:var(--border) transparent;}
.htp-tit{font-family:'Orbitron',sans-serif;font-size:24px;font-weight:900;color:#fff;letter-spacing:3px;margin-bottom:5px;}
.htp-s{font-size:13px;color:var(--text2);margin-bottom:26px;}
.htp-g{display:grid;grid-template-columns:1fr 1fr;gap:18px;}
.htpc{padding:22px;background:var(--card-bg);border:1px solid var(--border);position:relative;}
.htpc-ic{font-size:26px;margin-bottom:10px;}
.htpc-t{font-family:'Orbitron',sans-serif;font-size:13px;font-weight:700;color:#fff;margin-bottom:7px;}
.htpc-d{font-size:13px;color:var(--text2);line-height:1.7;}
.htp-sc{margin-top:22px;padding:22px;background:var(--card-bg);border:1px solid var(--border);}
.htp-sc-t{font-family:'Orbitron',sans-serif;font-size:13px;font-weight:700;color:var(--cyan);margin-bottom:14px;letter-spacing:2px;}
.sc-t{width:100%;border-collapse:collapse;}
.sc-t td{padding:8px 10px;border-bottom:1px solid rgba(255,255,255,0.04);font-size:13px;}
.sc-t td:last-child{text-align:right;font-family:'Share Tech Mono',monospace;color:var(--cyan);}

/* CORNER BTNS */
.cbtn{position:fixed;bottom:22px;padding:9px 22px;font-family:'Orbitron',sans-serif;font-size:10px;letter-spacing:2px;background:rgba(2,10,20,0.92);border:1px solid var(--border);color:var(--text2);cursor:pointer;transition:all .2s;z-index:200;}
.cbtn:hover{border-color:var(--cyan);color:var(--cyan);}
.cbtn.L{left:22px;}
.cbtn.R{right:22px;}

/* LOADING */
.loading{position:fixed;inset:0;background:var(--bg);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:9999;}
.l-logo{font-family:'Orbitron',sans-serif;font-size:52px;font-weight:900;color:var(--cyan);text-shadow:0 0 60px rgba(0,212,255,0.5);animation:glitch 2s infinite;}
.l-title{font-family:'Orbitron',sans-serif;font-size:11px;letter-spacing:6px;color:rgba(200,230,244,0.4);margin-top:7px;}
.l-bar-w{width:280px;height:2px;background:rgba(255,255,255,0.08);margin-top:28px;}
.l-bar{height:100%;background:var(--cyan);animation:loadBar 2s ease-in-out forwards;box-shadow:0 0 10px var(--cyan);}
.l-txt{font-family:'Share Tech Mono',monospace;font-size:10px;color:var(--text2);margin-top:10px;letter-spacing:2px;}

@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes fadeInUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:translateY(0)}}
@keyframes pulse{0%,100%{opacity:1}50%{opacity:0.4}}
@keyframes loadBar{from{width:0}to{width:100%}}
@keyframes glitch{0%,88%,100%{text-shadow:0 0 60px rgba(0,212,255,0.5)}92%{text-shadow:-3px 0 #f97316,3px 0 var(--purple),0 0 60px rgba(0,212,255,0.5)}96%{text-shadow:3px 0 #f97316,-3px 0 var(--purple),0 0 60px rgba(0,212,255,0.5)}}
`;

function cntWords(t) { return t.trim().split(/\s+/).filter(Boolean).length; }
function fallbackScore(text, kws) {
  const lower = text.toLowerCase();
  const w = cntWords(text);
  const kw = kws.filter(k => lower.includes(k)).length;
  return Math.min(100, Math.floor(w/3) + Math.min(30, kw*5) + Math.min(20, Math.floor(w/8)) + (w>150?10:w>100?5:0));
}

export default function App() {
  const [loading, setLoading] = useState(true);
  const [screen, setScreen] = useState("home");
  const [selChar, setSelChar] = useState(0);
  const [activeLv, setActiveLv] = useState(null);
  const [unlocked, setUnlocked] = useState([true,false,false,false,false]);
  const [scores, setScores] = useState({});
  const [subs, setSubs] = useState({});
  const [xp, setXp] = useState(2400);
  const [achs, setAchs] = useState(["first_solve"]);
  const [txt, setTxt] = useState("");
  const [timer, setTimer] = useState(0);
  const [timerOn, setTimerOn] = useState(false);
  const [showRes, setShowRes] = useState(false);
  const [result, setResult] = useState(null);
  const [evaluating, setEvaluating] = useState(false);
  const [stSec, setStSec] = useState("gameplay");
  const [settings, setSettings] = useState({sfx:true,music:true,timer:true,hints:true,difficulty:"normal"});
  const timerRef = useRef(null);

  useEffect(() => { setTimeout(() => setLoading(false), 2300); }, []);

  useEffect(() => {
    if (timerOn && timer > 0) {
      timerRef.current = setInterval(() => setTimer(t => {
        if (t <= 1) { clearInterval(timerRef.current); setTimerOn(false); return 0; }
        return t - 1;
      }), 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [timerOn]);

  const openLv = (lv) => {
    if (!unlocked[lv.id-1]) return;
    setActiveLv(lv); setTxt(subs[lv.id]||"");
    setTimer(lv.timeLimit); setTimerOn(true);
    setShowRes(false); setResult(null); setScreen("game");
  };

  const go = (s) => { setScreen(s); setShowRes(false); clearInterval(timerRef.current); setTimerOn(false); };

  const submit = async () => {
    if (!activeLv || evaluating) return;
    clearInterval(timerRef.current); setTimerOn(false); setEvaluating(true);
    const lv = activeLv;
    const ch = CHARACTERS.find(c => c.id === lv.char) || CHARACTERS[3];
    const timeTaken = lv.timeLimit - timer;
    const wc = cntWords(txt);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514", max_tokens:800,
          messages:[{ role:"user", content:
            "You are " + ch.name + ", a " + ch.role + " in 2050. Score this solution to the " + lv.title + " crisis (0-100).\nSolution: \"" + txt.substring(0,1500) + "\"\nRespond ONLY with valid JSON (no markdown): {\"score\":75,\"relevance\":22,\"innovation\":25,\"feasibility\":15,\"completeness\":13,\"charBonus\":5,\"feedback\":\"2-sentence feedback as the character in character voice.\"}"
          }]
        })
      });
      const data = await res.json();
      let r;
      try {
        const raw = (data.content||[]).find(x=>x.type==="text")?.text||"{}";
        r = JSON.parse(raw.replace(/```json|```/g,"").trim());
      } catch { r = null; }
      if (!r||typeof r.score!=="number") throw new Error("parse");
      const fs = Math.min(100, (r.score||0) + (r.charBonus||0));
      r.finalScore = fs; r.wordCount = wc; r.timeTaken = timeTaken;
      finalize(r, lv);
    } catch {
      const sc = fallbackScore(txt, lv.keywords);
      finalize({ score:sc, finalScore:sc, relevance:Math.floor(sc*.3), innovation:Math.floor(sc*.3), feasibility:Math.floor(sc*.2), completeness:Math.floor(sc*.2), charBonus:0, feedback:"Your solution demonstrates creative thinking. Keep exploring bold ideas to score higher!", wordCount:wc, timeTaken }, lv);
    }
    setEvaluating(false);
  };

  const finalize = (r, lv) => {
    setResult(r); setSubs(p=>({...p,[lv.id]:txt})); setScores(p=>({...p,[lv.id]:r.finalScore}));
    setXp(p => p + Math.floor(r.finalScore * 8));
    if (r.finalScore >= 40 && lv.id < 5) setUnlocked(p => { const n=[...p]; n[lv.id]=true; return n; });
    const na = [...achs];
    if (!na.includes("first_solve")) na.push("first_solve");
    if (r.wordCount>=200 && !na.includes("word_smith")) na.push("word_smith");
    if (r.finalScore>=90 && !na.includes("innovator")) na.push("innovator");
    if (r.timeTaken<=90 && !na.includes("speedrun")) na.push("speedrun");
    if (lv.id===5 && !na.includes("blueprint")) na.push("blueprint");
    const completed = Object.keys({...scores,[lv.id]:r.finalScore});
    if (completed.length>=5 && !na.includes("all_levels")) na.push("all_levels");
    setAchs(na); setShowRes(true);
  };

  const fmt = s => String(Math.floor(s/60)).padStart(2,"0")+":"+String(s%60).padStart(2,"0");
  const ch = CHARACTERS[selChar];
  const lv = activeLv;
  const lvCh = lv ? (CHARACTERS.find(c=>c.id===lv.char)||CHARACTERS[3]) : null;

  if (loading) return (
    <div className="loading">
      <style>{CSS}</style>
      <div className="bg-grid"/>
      <div className="l-logo">ETF</div>
      <div className="l-title">ESCAPE THE FUTURE</div>
      <div className="l-bar-w"><div className="l-bar"/></div>
      <div className="l-txt">INITIALISING CRISIS SIMULATION // 2050...</div>
    </div>
  );

  return (
    <div className="etf">
      <style>{CSS}</style>
      <div className="bg-grid"/>

      <nav className="navbar">
        <div className="nav-logo">ETF<span> // ESCAPE</span></div>
        <div className="nav-links">
          {[["home","HOME"],["characters","CHARS"],["levels","LEVELS"],["achievements","ACHIEVEMENTS"]].map(([s,l])=>(
            <div key={s} className={`nl${screen===s?" active":""}`} onClick={()=>go(s)}>{l}</div>
          ))}
          <div className={`nl${screen==="settings"?" active":""}`} onClick={()=>go("settings")}>SETTINGS</div>
          <div className={`nl${screen==="howtoplay"?" active":""}`} onClick={()=>go("howtoplay")}>HOW TO PLAY</div>
        </div>
        <div className="nav-r">
          <span className="nav-xp">⚡{xp.toLocaleString()} XP</span>
          <span className="nb">{achs.length} BADGES</span>
          <span className="nb" style={{color:"var(--cyan)"}}>{Object.keys(scores).length}/5 LVL</span>
        </div>
      </nav>

      <div className="content">
        {/* HOME */}
        {screen==="home"&&(
          <div className="home">
            <div className="home-bg"/>
            <div style={{position:"absolute",inset:0,background:"radial-gradient(ellipse at 50% 100%,rgba(0,80,180,0.1) 0%,transparent 65%)"}}/>
            <div className="home-title">
              <div className="eyebrow">// YEAR 2050 // CRISIS SIMULATION //</div>
              <h1 className="h1"><span className="l1">ESCAPE</span><span className="l2">THE FUTURE</span></h1>
              <div className="home-sub">Solve 5 Global Crises · Earn Your Escape Portal</div>
            </div>
            <div className="home-chars">
              {CHARACTERS.map((c,i)=>(
                <div key={c.id} className="hcm" onClick={()=>{setSelChar(i);go("characters");}}>
                  <img src={IMG[c.id]} alt={c.name} className="hcm-img" style={{borderColor:c.color}}/>
                  <div className="hcm-name" style={{color:c.color}}>{c.badge}</div>
                </div>
              ))}
            </div>
            <div className="home-cta">
              <button className="btn-p" onClick={()=>go("characters")}>▶ START GAME</button>
              <button className="btn-s" onClick={()=>go("howtoplay")}>HOW TO PLAY</button>
            </div>
            <div className="home-stats">
              {[["5","CRISIS LEVELS"],["4","AI MENTORS"],["∞","IDEAS"]].map(([n,l])=>(
                <div key={l} className="stat"><div className="stat-n">{n}</div><div className="stat-l">{l}</div></div>
              ))}
            </div>
          </div>
        )}

        {/* CHARACTERS */}
        {screen==="characters"&&(
          <div className="chars-screen">
            <div className="cs-bg-img" style={{backgroundImage:`url(${IMG[ch.id]})`}}/>
            <div className="cs-overlay"/>
            <div className="cs-left">
              <div className="cs-header">
                <div className="cs-tabs">
                  {["ALL 4","RECENT 2","FREQUENT 1"].map((t,i)=>(
                    <div key={t} className={`cs-tab${i===0?" act":""}`}>{t}</div>
                  ))}
                </div>
                <div className="cs-title" style={{color:ch.color}}>{ch.name}</div>
              </div>
              <div className="cs-strip">
                {CHARACTERS.map((c,i)=>(
                  <div key={c.id} className={`cc${i===selChar?" sel":""}`}
                    style={{"--cc":c.color,"--cg":c.glow}}
                    onClick={()=>setSelChar(i)}>
                    <div className="cc-inner" style={{borderColor:i===selChar?c.color:"rgba(255,255,255,0.1)"}}>
                      <img src={IMG[c.id]} alt={c.name} className="cc-img"/>
                      <div className="cc-lbl">
                        {c.name.split(" ").slice(-1)[0].toUpperCase()}
                        <div className="cc-pts" style={{color:c.color}}>{c.level}/{c.maxLevel}</div>
                      </div>
                    </div>
                    {i===1&&<div className="new-badge">NEW</div>}
                  </div>
                ))}
              </div>
              <div className="cs-detail" style={{"--cc":ch.color,"--cg":ch.glow}}>
                <div className="cs-badge" style={{borderColor:ch.color,color:ch.color}}>◆ {ch.badge} ◆</div>
                <div className="cs-quote" style={{borderColor:ch.color}}>"{ch.quote}"</div>
                <div className="nature-wrap">
                  {ch.nature.map(n=><div key={n} className="nt">{n}</div>)}
                </div>
                <div className="bonus-box">
                  <div className="bonus-t">// MINDSET BONUS AREAS</div>
                  <div className="bonus-v" style={{color:ch.color}}>{ch.bonus}</div>
                </div>
                <div>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:"11px",color:"var(--text2)",marginBottom:"4px"}}>
                    <span style={{fontFamily:"Orbitron,sans-serif",fontSize:"9px",letterSpacing:"2px"}}>LV.{ch.level}/{ch.maxLevel}</span>
                    <span style={{fontFamily:"Share Tech Mono,monospace"}}>{ch.xp.toLocaleString()} XP</span>
                  </div>
                  <div className="xp-bar">
                    <div className="xp-fill" style={{width:`${(ch.level/ch.maxLevel)*100}%`,background:ch.color}}/>
                  </div>
                </div>
                <div className="stars">
                  {"★★★★★".split("").map((_,i)=>(
                    <span key={i} style={{fontSize:"14px",color:i<ch.stars?ch.color:"rgba(255,255,255,0.15)"}}>★</span>
                  ))}
                </div>
                <div className="cs-actions">
                  <button className="btn-p" style={{background:ch.color}} onClick={()=>go("levels")}>▶ PLAY</button>
                  <button className="btn-s" style={{color:ch.color,borderColor:ch.color}} onClick={()=>go("levels")}>VIEW LEVELS</button>
                </div>
              </div>
            </div>
            <div className="cs-right">
              <img src={IMG[ch.id]} alt={ch.name} className="cs-full"/>
              <div className="cs-right-ov"/>
              <div className="cs-ri">
                <div className="cs-ri-role" style={{color:ch.color}}>{ch.badge}</div>
                <div className="cs-ri-name">{ch.name}</div>
                <div className="stars" style={{justifyContent:"flex-end",marginTop:"6px"}}>
                  {"★★★★★".split("").map((_,i)=>(
                    <span key={i} style={{fontSize:"13px",color:i<ch.stars?ch.color:"rgba(255,255,255,0.15)"}}>★</span>
                  ))}
                </div>
              </div>
              <div style={{position:"absolute",top:"36px",left:"36px"}}>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"9px",letterSpacing:"3px",color:ch.color,marginBottom:"7px"}}>CHARACTER INFO</div>
                <div style={{padding:"7px 14px",background:"rgba(0,0,0,0.65)",border:`1px solid ${ch.color}`}}>
                  <div style={{fontFamily:"Share Tech Mono,monospace",fontSize:"12px",color:ch.color}}>LV.{ch.level} // {ch.xp.toLocaleString()} XP</div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* LEVELS */}
        {screen==="levels"&&(
          <div className="lvls">
            <div className="lvls-hdr">
              <div className="lvls-title">// CRISIS LEVELS</div>
              <div className="lvls-sub">Select a crisis. Solve it with innovative ideas. Score 40+ to unlock the next level.</div>
            </div>
            <div className="lvls-grid">
              {LEVELS.map(l=>{
                const isOpen = unlocked[l.id-1];
                const sc = scores[l.id];
                const lc = CHARACTERS.find(c=>c.id===l.char);
                return (
                  <div key={l.id} className={`lcard${isOpen?" open":" locked"}${l.id===5?" final":""}`}
                    style={{"--lc":l.color}} onClick={()=>isOpen&&openLv(l)}>
                    {sc!=null&&<div className="lv-sc" style={{color:l.color,borderColor:l.color}}>{sc}/100</div>}
                    <div className="lv-sub" style={{color:l.color}}>{l.subtitle}</div>
                    <div className="lv-icon">{l.icon}</div>
                    <div className="lv-title" style={{color:l.id===5?l.color:"#fff"}}>{l.title}</div>
                    <div className="lv-desc">{l.crisis}</div>
                    {lc&&<div className="lv-char">
                      <img src={IMG[lc.id]} alt={lc.name} className="lv-char-img" style={{borderColor:l.color}}/>
                      <div className="lv-char-n" style={{color:l.color}}>{lc.name.split(" ")[0]}</div>
                    </div>}
                    {!isOpen&&<div className="lv-lock">🔒</div>}
                    <div className="lv-prog">
                      <div className="lv-prog-fill" style={{width:sc?`${sc}%`:"0%",background:l.color}}/>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* GAME */}
        {screen==="game"&&lv&&(
          <div className="game" style={{"--gc":lvCh?.color||"var(--cyan)"}}>
            <div className="g-sidebar">
              {lvCh&&<img src={IMG[lvCh.id]} alt={lvCh.name} className="g-portrait" style={{border:`1px solid ${lvCh.color}`}}/>}
              <div className="g-badge" style={{borderColor:lvCh?.color,color:lvCh?.color}}>{lvCh?.badge||"AI MENTOR"}</div>
              <div><div className="g-cname">{lvCh?.name||"AI Mentor"}</div><div className="g-crole">{lvCh?.role||""}</div></div>
              <div className="g-bonus">
                <div className="g-bonus-t">// BONUS FOR</div>
                <div className="g-bonus-v" style={{color:lvCh?.color}}>{lvCh?.bonus||"Creative solutions"}</div>
              </div>
              <div className="g-tips">
                <b style={{color:lvCh?.color}}>💡 TIPS</b><br/><br/>
                • Write at least <b style={{color:"#fff"}}>{lv.minWords} words</b><br/>
                • Be specific &amp; creative<br/>
                • Think like {lvCh?.name?.split(" ")[0]||"your mentor"}<br/>
                • Mention real technologies<br/><br/>
                <b style={{color:lvCh?.color}}>⏱ TIME LIMIT</b><br/>
                {Math.floor(lv.timeLimit/60)} minutes
              </div>
            </div>
            <div className="g-main">
              <div className="g-lbadge" style={{color:lvCh?.color}}>{lv.subtitle} — {lv.title.toUpperCase()}</div>
              <div className="g-ctitle">{lv.crisis}</div>
              <div className="g-ctx">{lv.context}</div>
              <div className="g-task">
                <div className="g-task-l" style={{color:lvCh?.color}}>// YOUR MISSION</div>
                <div className="g-task-t">{lv.task}</div>
              </div>
              <div className="g-input-area">
                <textarea className="g-ta"
                  placeholder="Write your innovative solutions here... Be specific, reference real technologies, and think beyond conventional approaches. The future of humanity depends on your ideas."
                  value={txt} onChange={e=>setTxt(e.target.value)}
                  disabled={showRes||evaluating}/>
              </div>
              <div className="g-footer">
                <div className={`g-wc${cntWords(txt)>=lv.minWords?" ok":""}`}>
                  {cntWords(txt)}/{lv.minWords} words {cntWords(txt)>=lv.minWords?"✓":""}
                </div>
                <div className={`g-timer${timer<=30?"danger":timer<=60?"warn":""}`}>{fmt(timer)}</div>
                <button className="g-sub" style={{background:lvCh?.color||"var(--cyan)"}}
                  disabled={cntWords(txt)<lv.minWords||evaluating||showRes} onClick={submit}>
                  {evaluating?"EVALUATING...":"▶ SUBMIT"}
                </button>
                <button className="g-exit" onClick={()=>go("levels")}>← EXIT</button>
              </div>

              {showRes&&result&&(
                <div className="res-ov">
                  <div className="res-box" style={{"--gc":lvCh?.color||"var(--cyan)"}}>
                    <div className="res-title" style={{color:result.finalScore>=70?lvCh?.color||"var(--cyan)":"#f97316"}}>
                      {result.finalScore>=80?"🎉 OUTSTANDING!":result.finalScore>=60?"✅ SOLUTION ACCEPTED":"⚠️ NEEDS MORE DEPTH"}
                    </div>
                    <div className="res-ring">
                      <svg viewBox="0 0 110 110" width="110" height="110">
                        <circle cx="55" cy="55" r="46" fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="8"/>
                        <circle cx="55" cy="55" r="46" fill="none" stroke={lvCh?.color||"var(--cyan)"} strokeWidth="8"
                          strokeDasharray={`${(result.finalScore/100)*289} 289`} strokeLinecap="round"
                          style={{filter:`drop-shadow(0 0 6px ${lvCh?.color||"var(--cyan)"})`}}/>
                      </svg>
                      <div className="res-num" style={{color:lvCh?.color||"var(--cyan)"}}>{result.finalScore}</div>
                    </div>
                    <div className="res-br">
                      {[["Relevance",result.relevance,30],["Innovation",result.innovation,30],["Feasibility",result.feasibility,20],["Complete",result.completeness,20]].map(([l2,v,m])=>(
                        <div key={l2} className="rb"><span>{l2}</span><span className="rb-v" style={{color:lvCh?.color}}>{v}/{m}</span></div>
                      ))}
                      <div className="rb" style={{gridColumn:"span 2"}}><span>Words</span><span className="rb-v" style={{color:lvCh?.color}}>{result.wordCount}</span></div>
                    </div>
                    <div className="res-fb">
                      <b style={{color:lvCh?.color}}>— {lvCh?.name||"AI Mentor"}:</b><br/>"{result.feedback}"
                    </div>
                    <div className="res-acts">
                      {result.finalScore>=40&&lv.id<5&&(
                        <button className="btn-p" style={{background:lvCh?.color}} onClick={()=>go("levels")}>NEXT LEVEL →</button>
                      )}
                      <button className="btn-s" onClick={()=>{setShowRes(false);setTxt("");}}>RETRY</button>
                      <button className="btn-s" onClick={()=>go("levels")}>LEVELS</button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* ACHIEVEMENTS */}
        {screen==="achievements"&&(
          <div className="ach">
            <div className="a-title">// ACHIEVEMENTS</div>
            <div className="a-sub">Unlock badges by solving crises creatively. Each badge earns XP toward your escape.</div>
            <div className="a-grid">
              {ACHIEVEMENTS.map(a=>{
                const e = achs.includes(a.id);
                return (
                  <div key={a.id} className={`acard${e?" earned":""}`}>
                    <div className="a-icon" style={{filter:e?"none":"grayscale(1) opacity(0.3)"}}>{a.icon}</div>
                    <div className="a-t" style={{color:e?"#fff":"var(--text2)"}}>{a.title}</div>
                    <div className="a-d">{a.desc}</div>
                    <div className="a-xp" style={{color:e?"var(--gold)":"var(--text2)"}}>{e?"✓ ":""}{a.xp} XP</div>
                    {!e&&<div className="a-lock">🔒</div>}
                  </div>
                );
              })}
            </div>
            <div className="a-bar-wrap">
              <div>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"10px",letterSpacing:"2px",color:"var(--text2)",marginBottom:"5px"}}>ACHIEVEMENTS</div>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"26px",fontWeight:"900",color:"var(--gold)"}}>{achs.length}/{ACHIEVEMENTS.length}</div>
              </div>
              <div className="a-bar"><div className="a-bar-fill" style={{width:`${(achs.length/ACHIEVEMENTS.length)*100}%`}}/></div>
              <div style={{fontFamily:"Share Tech Mono,monospace",fontSize:"14px",color:"var(--gold)"}}>{Math.floor((achs.length/ACHIEVEMENTS.length)*100)}%</div>
            </div>
          </div>
        )}

        {/* SETTINGS */}
        {screen==="settings"&&(
          <div className="settings">
            <div className="st-left">
              <div className="st-title">// SETTINGS</div>
              {[["gameplay","🎮","GAMEPLAY"],["audio","🔊","AUDIO"],["display","🖥","DISPLAY"],["account","👤","ACCOUNT"]].map(([s,ic,l])=>(
                <div key={s} className={`st-sec${stSec===s?" act":""}`} onClick={()=>setStSec(s)}>
                  <span className="st-sec-ic">{ic}</span><span className="st-sec-l">{l}</span>
                </div>
              ))}
            </div>
            <div className="st-right">
              {stSec==="gameplay"&&<>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"13px",color:"var(--cyan)",letterSpacing:"2px",marginBottom:"18px"}}>GAMEPLAY</div>
                {[["Show Timer","timer"],["Show Hints","hints"]].map(([l,k])=>(
                  <div key={k} className="st-row"><span className="st-row-l">{l}</span>
                  <div className={`toggle${settings[k]?" on":""}`} onClick={()=>setSettings(p=>({...p,[k]:!p[k]}))}/>
                  </div>
                ))}
                <div className="st-row"><span className="st-row-l">Difficulty</span>
                  <select className="st-sel" value={settings.difficulty} onChange={e=>setSettings(p=>({...p,difficulty:e.target.value}))}>
                    <option value="easy">Easy</option><option value="normal">Normal</option><option value="hard">Hard</option>
                  </select>
                </div>
              </>}
              {stSec==="audio"&&<>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"13px",color:"var(--cyan)",letterSpacing:"2px",marginBottom:"18px"}}>AUDIO</div>
                {[["Sound Effects","sfx"],["Music","music"]].map(([l,k])=>(
                  <div key={k} className="st-row"><span className="st-row-l">{l}</span>
                  <div className={`toggle${settings[k]?" on":""}`} onClick={()=>setSettings(p=>({...p,[k]:!p[k]}))}/>
                  </div>
                ))}
                <div className="st-row"><span className="st-row-l">Volume</span><input type="range" className="st-slider" min="0" max="100" defaultValue="70"/></div>
              </>}
              {stSec==="display"&&<>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"13px",color:"var(--cyan)",letterSpacing:"2px",marginBottom:"18px"}}>DISPLAY</div>
                {[["Scanlines","scanlines"],["Grid Background","grid"],["Glow Effects","glow"]].map(([l,k])=>(
                  <div key={k} className="st-row"><span className="st-row-l">{l}</span><div className="toggle on"/></div>
                ))}
                <div className="st-row"><span className="st-row-l">Glow Intensity</span><input type="range" className="st-slider" min="0" max="100" defaultValue="80"/></div>
              </>}
              {stSec==="account"&&<>
                <div style={{fontFamily:"Orbitron,sans-serif",fontSize:"13px",color:"var(--cyan)",letterSpacing:"2px",marginBottom:"18px"}}>ACCOUNT</div>
                {[["Player ID","ETF-2050-001"],["Total XP",xp.toLocaleString()+" XP"],["Levels Done",Object.keys(scores).length+"/5"],["Achievements",achs.length+"/"+ACHIEVEMENTS.length]].map(([l,v])=>(
                  <div key={l} className="st-row"><span className="st-row-l">{l}</span><span style={{fontFamily:"Share Tech Mono,monospace",fontSize:"12px",color:"var(--cyan)"}}>{v}</span></div>
                ))}
                <div style={{marginTop:"20px"}}>
                  <button className="btn-s" style={{fontSize:"10px",padding:"9px 18px"}}
                    onClick={()=>{if(confirm("Reset all progress?")){setScores({});setSubs({});setXp(0);setUnlocked([true,false,false,false,false]);setAchs([]);}}}>
                    RESET PROGRESS
                  </button>
                </div>
              </>}
            </div>
          </div>
        )}

        {/* HOW TO PLAY */}
        {screen==="howtoplay"&&(
          <div className="htp">
            <div className="htp-tit">// HOW TO PLAY</div>
            <div className="htp-s">Your mission: solve 5 global crises using innovative thinking and earn your portal back to 2026.</div>
            <div className="htp-g">
              {[["🧑‍🚀","1. Choose Your Mentor","Select from 4 AI survivors of 2050. Each has a unique mindset — Engineering, Ecology, Strategy, or Innovation. Match their thinking style for bonus XP."],
                ["📋","2. Read the Crisis","Each level presents a brutal future crisis. Study the context carefully. Understanding the problem depth leads to better scored solutions."],
                ["✍️","3. Write Your Solution","Type at least the minimum word count. Be specific and reference real technologies. The more detailed and creative, the higher your score."],
                ["🤖","4. AI Evaluates You","Your solution is scored live by Claude AI — measuring relevance, innovation, feasibility, completeness, and character mindset match."],
                ["🔓","5. Unlock Levels","Score 40+ to unlock the next crisis. Higher scores earn more XP and achievements. Retry as many times as needed."],
                ["🏆","6. Escape the Future","Complete all 5 levels. In the Final Level, write a unified Future Survival Blueprint to unlock the escape portal and return to 2026."]
              ].map(([ic,t,d])=>(
                <div key={t} className="htpc">
                  <div className="htpc-ic">{ic}</div>
                  <div className="htpc-t">{t}</div>
                  <div className="htpc-d">{d}</div>
                </div>
              ))}
            </div>
            <div className="htp-sc">
              <div className="htp-sc-t">// SCORING BREAKDOWN</div>
              <table className="sc-t">
                <tbody>
                  {[["Base Points (word count)","0–40"],["Keyword Relevance","0–30"],["Innovation Score (AI)","0–20"],["Character Mindset Bonus","0–10"],["Speed Bonus","0–5"],["Word Count Bonus (150+ words)","0–10"]].map(([l,v])=>(
                    <tr key={l}><td>{l}</td><td>{v}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>

      {screen!=="home"&&<button className="cbtn L" onClick={()=>{const o=["home","characters","levels","achievements","settings","howtoplay"];const i=o.indexOf(screen);if(i>0)go(o[i-1]);}}>◀ BACK</button>}
      {screen!=="howtoplay"&&screen!=="game"&&<button className="cbtn R" onClick={()=>{const o=["home","characters","levels","achievements","settings","howtoplay"];const i=o.indexOf(screen);if(i<o.length-1)go(o[i+1]);}}>NEXT ▶</button>}
    </div>
  );
}
